import { GoogleGenAI } from "@google/genai";

export const generateLeaveReason = async (eventName: string, startDate: string, endDate: string, studentName: string): Promise<string> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const prompt = `
      Write a professional, concise (2-3 sentences) leave application reason for a university student.
      Student Name: ${studentName}
      Event Name: ${eventName}
      Event Duration: From ${startDate} to ${endDate}

      The tone should be academic and polite, requesting approval to attend. Do not include placeholders.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text || "I would like to request leave to attend this upcoming event.";
  } catch (error) {
    console.error("Gemini generation error:", error);
    return "I request leave to attend this educational event.";
  }
};

import React, { useState } from 'react';
import { storageService } from '../services/storageService';
import { User, Role } from '../types';
import { Button } from '../components/Button';
import { GraduationCap, Briefcase, UserPlus, Loader2, Database } from 'lucide-react';

interface LoginProps {
  onLogin: (user: User) => void;
}

export const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [activeTab, setActiveTab] = useState<Role>('STUDENT');
  const [isRegistering, setIsRegistering] = useState(false);
  const [loading, setLoading] = useState(false);
  const [initializing, setInitializing] = useState(false);

  // Form State
  const [identifier, setIdentifier] = useState('');
  const [password, setPassword] = useState('');
  const [regName, setRegName] = useState('');
  const [regUsn, setRegUsn] = useState('');
  const [regPass, setRegPass] = useState('');
  const [error, setError] = useState('');
  const [successMsg, setSuccessMsg] = useState('');
  const [dbEmpty, setDbEmpty] = useState(false);

  const inputClasses = "w-full px-4 py-3 bg-white border border-gray-200 rounded-lg focus:ring-2 focus:ring-orange-500 focus:border-transparent outline-none transition-all text-gray-900 placeholder-gray-400 shadow-sm";

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccessMsg('');
    setDbEmpty(false);
    setLoading(true);

    try {
      const user = await storageService.login(identifier.trim(), password);

      if (user) {
        const isStudentTab = activeTab === 'STUDENT';
        const isTeacherTab = activeTab === 'TEACHER';
        const isStudentUser = user.role === 'STUDENT';
        const isStaffUser = user.role === 'TEACHER' || user.role === 'HOD';

        if (isStudentTab && isStudentUser) {
          onLogin(user);
        } else if (isTeacherTab && isStaffUser) {
          onLogin(user);
        } else {
          setError(`Found account but role is ${user.role}. Please switch tabs.`);
        }
      } else {
        const allUsers = await storageService.getUsers();
        if (allUsers.length === 0) {
             setError('Database is empty. Please initialize system data.');
             setDbEmpty(true);
        } else {
             setError('Invalid credentials. Please check your inputs.');
        }
      }
    } catch (err) {
      setError('An error occurred during login. Check your connection.');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleInitialize = async () => {
    setInitializing(true);
    setError('');
    try {
      const msg = await storageService.seedStudents();
      setSuccessMsg(msg);
      setDbEmpty(false);
    } catch (err) {
      setError('Failed to initialize database.');
      console.error(err);
    } finally {
      setInitializing(false);
    }
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccessMsg('');

    if (regName && regUsn && regPass) {
      setLoading(true);
      try {
        const newUser = await storageService.registerStudent(regName.trim(), regUsn.trim(), regPass);
        onLogin(newUser);
      } catch (err: any) {
        setError(err.message || 'Registration failed.');
      } finally {
        setLoading(false);
      }
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-orange-50 to-orange-100 flex items-center justify-center p-4 relative">
      <div className="bg-white rounded-2xl shadow-xl w-full max-w-md overflow-hidden z-10 border border-gray-100">

        <div className="flex border-b border-gray-100">
          <button
            onClick={() => { setActiveTab('STUDENT'); setIsRegistering(false); setError(''); setSuccessMsg(''); setDbEmpty(false); }}
            className={`flex-1 py-4 text-sm font-semibold flex items-center justify-center gap-2 transition-colors ${
              activeTab === 'STUDENT' ? 'bg-orange-50 text-orange-600 border-b-2 border-orange-600' : 'text-gray-500 hover:text-gray-700 bg-gray-50/50'
            }`}
          >
            <GraduationCap className="w-4 h-4" /> Student
          </button>
          <button
            onClick={() => { setActiveTab('TEACHER'); setIsRegistering(false); setError(''); setSuccessMsg(''); setDbEmpty(false); }}
            className={`flex-1 py-4 text-sm font-semibold flex items-center justify-center gap-2 transition-colors ${
              activeTab === 'TEACHER' ? 'bg-orange-50 text-orange-600 border-b-2 border-orange-600' : 'text-gray-500 hover:text-gray-700 bg-gray-50/50'
            }`}
          >
            <Briefcase className="w-4 h-4" /> Faculty / HOD
          </button>
        </div>

        <div className="p-8">
          <div className="text-center mb-8">
            <h1 className="text-2xl font-bold text-gray-800">
              {activeTab === 'STUDENT' ? (isRegistering ? 'Student Registration' : 'Student Login') : 'Faculty Portal'}
            </h1>
            <p className="text-gray-500 text-sm mt-2">
              {activeTab === 'STUDENT' 
                ? 'Manage your event leave applications' 
                : 'Review and manage student requests'}
            </p>
          </div>

          {error && (
            <div className="bg-red-50 text-red-600 text-sm p-4 rounded-lg mb-4 text-center border border-red-100 animate-fade-in flex flex-col items-center gap-3">
              <span>{error}</span>
              {dbEmpty && (
                <button 
                  onClick={handleInitialize}
                  disabled={initializing}
                  className="flex items-center gap-2 bg-red-600 text-white px-4 py-2 rounded-lg text-xs font-bold hover:bg-red-700 transition-colors shadow-md disabled:opacity-50"
                >
                  {initializing ? <Loader2 className="w-3 h-3 animate-spin" /> : <Database className="w-3 h-3" />}
                  Initialize System Now
                </button>
              )}
            </div>
          )}

          {successMsg && (
            <div className="bg-green-50 text-green-600 text-sm p-3 rounded-lg mb-4 text-center border border-green-100 animate-fade-in">
              {successMsg}
            </div>
          )}

          {activeTab === 'STUDENT' && isRegistering ? (
            <form onSubmit={handleRegister} className="space-y-4">
               <div>
                <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 mb-1.5">Full Name</label>
                <input
                  type="text"
                  required
                  placeholder="Enter Full Name"
                  className={inputClasses}
                  value={regName}
                  onChange={(e) => setRegName(e.target.value)}
                  disabled={loading || initializing}
                />
              </div>
              <div>
                <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 mb-1.5">USN</label>
                <input
                  type="text"
                  required
                  placeholder="Enter USN"
                  className={inputClasses}
                  value={regUsn}
                  onChange={(e) => setRegUsn(e.target.value)}
                  disabled={loading || initializing}
                />
              </div>
              <div>
                <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 mb-1.5">Password</label>
                <input
                  type="password"
                  required
                  placeholder="Create Password"
                  className={inputClasses}
                  value={regPass}
                  onChange={(e) => setRegPass(e.target.value)}
                  disabled={loading || initializing}
                />
              </div>
              <Button type="submit" fullWidth disabled={loading || initializing} className="mt-2">
                 {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : 'Create Account'}
              </Button>
              <div className="text-center mt-4">
                <button type="button" onClick={() => setIsRegistering(false)} className="text-sm text-orange-600 hover:underline" disabled={loading || initializing}>
                  Already have an account? Login
                </button>
              </div>
            </form>
          ) : (
            <form onSubmit={handleLogin} className="space-y-4">
              <div>
                <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 mb-1.5">
                  {activeTab === 'STUDENT' ? 'USN / Name' : 'Faculty ID / Name'}
                </label>
                <input
                  type="text"
                  required
                  placeholder={activeTab === 'STUDENT' ? 'Enter USN or Name' : 'Enter Faculty Name'}
                  className={inputClasses}
                  value={identifier}
                  onChange={(e) => setIdentifier(e.target.value)}
                  disabled={loading || initializing}
                />
              </div>
              <div>
                <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 mb-1.5">Password</label>
                <input
                  type="password"
                  required
                  placeholder="Enter Password"
                  className={inputClasses}
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  disabled={loading || initializing}
                />
              </div>

              <Button type="submit" fullWidth disabled={loading || initializing} className="mt-2">
                {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : 'Sign In'}
              </Button>

              {activeTab === 'STUDENT' && (
                <div className="text-center mt-3">
                  <button type="button" onClick={() => setIsRegistering(true)} className="text-sm text-orange-600 hover:underline flex items-center justify-center gap-1 mx-auto font-medium" disabled={loading || initializing}>
                    <UserPlus className="w-4 h-4" /> New Student? Register
                  </button>
                </div>
              )}
            </form>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Login } from './pages/Login';
import { StudentDashboard } from './pages/StudentDashboard';
import { TeacherDashboard } from './pages/TeacherDashboard';
import { User } from './types';
import { storageService } from './services/storageService';
import { isSupabaseConfigured } from './services/supabaseClient';
import { Database, AlertTriangle, Loader2, Sparkles } from 'lucide-react';

function App() {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isConfigured, setIsConfigured] = useState(true);
  const [needsInit, setNeedsInit] = useState(false);
  const [isInitializing, setIsInitializing] = useState(false);

  // Check session and configuration on mount
  useEffect(() => {
    if (!isSupabaseConfigured()) {
      setIsConfigured(false);
      setIsLoading(false);
      return;
    }

    const startupCheck = async () => {
      try {
        // 1. Check for existing session
        const session = localStorage.getItem('unievent_session');
        if (session) {
          setUser(JSON.parse(session));
        }

        // 2. Check if DB is empty
        const allUsers = await storageService.getUsers();
        if (allUsers.length === 0) {
          setNeedsInit(true);
        }
      } catch (err) {
        console.error("Startup check failed", err);
      } finally {
        setIsLoading(false);
      }
    };
    startupCheck();
  }, []);

  const handleLogin = (loggedInUser: User) => {
    setUser(loggedInUser);
    localStorage.setItem('unievent_session', JSON.stringify(loggedInUser));
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('unievent_session');
  };

  const handleInitialize = async () => {
    setIsInitializing(true);
    try {
      await storageService.seedStudents();
      setNeedsInit(false);
    } catch (error) {
      console.error("Initialization failed", error);
      alert("Failed to initialize system. Check your Supabase tables.");
    } finally {
      setIsInitializing(false);
    }
  };

  // Setup Screen (Shown if keys are missing)
  if (!isConfigured) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50 p-4">
        <div className="max-w-md w-full bg-white rounded-2xl shadow-xl p-8 border border-orange-100 text-center">
          <div className="w-16 h-16 bg-orange-100 text-orange-600 rounded-full flex items-center justify-center mx-auto mb-6">
            <Database className="w-8 h-8" />
          </div>
          <h1 className="text-2xl font-bold text-gray-900 mb-2">Connect Database</h1>
          <p className="text-gray-600 mb-6">
            To use UniEvent, you need to connect your Supabase database.
          </p>

          <div className="bg-yellow-50 border border-yellow-200 rounded-lg p-4 text-left mb-6">
            <div className="flex gap-2 text-yellow-800 font-semibold mb-2 items-center">
              <AlertTriangle className="w-4 h-4" /> Action Required
            </div>
            <p className="text-sm text-yellow-700 mb-2">
              Open <code className="bg-yellow-100 px-1 py-0.5 rounded font-mono text-yellow-900">services/supabaseClient.ts</code>
            </p>
            <ol className="list-decimal list-inside text-sm text-yellow-700 space-y-1">
              <li>Paste your <b>Project URL</b></li>
              <li>Paste your <b>Anon Key</b></li>
            </ol>
          </div>

          <button 
            onClick={() => window.location.reload()} 
            className="w-full bg-orange-600 text-white font-bold py-3 rounded-xl hover:bg-orange-700 transition-colors shadow-lg shadow-orange-200"
          >
            I've Updated the Code
          </button>
        </div>
      </div>
    );
  }

  // Initialization Screen (Shown if DB is empty)
  if (needsInit && !user) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-orange-50 p-4">
        <div className="max-w-md w-full bg-white rounded-3xl shadow-2xl p-10 text-center border border-orange-100">
           <div className="w-20 h-20 bg-orange-600 text-white rounded-2xl flex items-center justify-center mx-auto mb-6 rotate-3 shadow-lg">
              <Sparkles className="w-10 h-10" />
           </div>
           <h1 className="text-3xl font-extrabold text-gray-900 mb-3 tracking-tight">Welcome to UniEvent</h1>
           <p className="text-gray-500 mb-8 leading-relaxed">
             The system is ready, but the database is empty. Let's initialize the demo accounts and students to get you started.
           </p>

           <div className="space-y-4">
             <button 
                onClick={handleInitialize} 
                disabled={isInitializing}
                className="w-full bg-orange-600 text-white font-bold py-4 rounded-2xl hover:bg-orange-700 transition-all shadow-xl shadow-orange-200 flex items-center justify-center gap-3 active:scale-95 disabled:opacity-50"
             >
               {isInitializing ? (
                 <>
                   <Loader2 className="w-5 h-5 animate-spin" />
                   Initializing...
                 </>
               ) : (
                 'Initialize System Data'
               )}
             </button>
             <p className="text-[10px] text-gray-400 uppercase tracking-widest font-bold">
               Creates HOD, 2 Teachers, and 53 Students
             </p>
           </div>
        </div>
      </div>
    );
  }

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50 flex-col gap-4">
        <div className="w-10 h-10 border-4 border-orange-200 border-t-orange-600 rounded-full animate-spin"></div>
        <div className="text-gray-400 font-medium">Loading UniEvent...</div>
      </div>
    );
  }

  if (!user) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <>
      {user.role === 'STUDENT' ? (
        <StudentDashboard user={user} onLogout={handleLogout} />
      ) : (
        <TeacherDashboard user={user} onLogout={handleLogout} />
      )}
    </>
  );
}

export default App;

