import React, { useState } from 'react';
import { storageService } from '../services/storageService';
import { User, Role } from '../types';
import { Button } from '../components/Button';
import { GraduationCap, Briefcase, UserPlus, Loader2, Database, ShieldAlert } from 'lucide-react';

interface LoginProps {
  onLogin: (user: User) => void;
}

export const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [activeTab, setActiveTab] = useState<Role>('STUDENT');
  const [isRegistering, setIsRegistering] = useState(false);
  const [loading, setLoading] = useState(false);
  const [initializing, setInitializing] = useState(false);

  // Form State
  const [identifier, setIdentifier] = useState('');
  const [password, setPassword] = useState('');
  const [regName, setRegName] = useState('');
  const [regUsn, setRegUsn] = useState('');
  const [regPass, setRegPass] = useState('');
  const [error, setError] = useState('');
  const [successMsg, setSuccessMsg] = useState('');
  const [dbEmpty, setDbEmpty] = useState(false);

  const inputClasses = "w-full px-4 py-3 bg-white border border-gray-200 rounded-xl focus:ring-2 focus:ring-orange-500 focus:border-transparent outline-none transition-all text-gray-900 placeholder-gray-400 shadow-sm font-medium";

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccessMsg('');
    setDbEmpty(false);
    setLoading(true);

    try {
      const user = await storageService.login(identifier.trim(), password);

      if (user) {
        const isStudentTab = activeTab === 'STUDENT';
        const isTeacherTab = activeTab === 'TEACHER';
        const isStudentUser = user.role === 'STUDENT';
        const isStaffUser = user.role === 'TEACHER' || user.role === 'HOD';

        if (isStudentTab && isStudentUser) {
          onLogin(user);
        } else if (isTeacherTab && isStaffUser) {
          onLogin(user);
        } else {
          setError(`Found account, but please use the ${user.role === 'STUDENT' ? 'Student' : 'Faculty'} tab.`);
        }
      } else {
        const allUsers = await storageService.getUsers();
        if (allUsers.length === 0) {
             setError('System not initialized. Database is empty.');
             setDbEmpty(true);
        } else {
             setError('Invalid credentials. Please try again.');
        }
      }
    } catch (err) {
      setError('Connection error. Please check your Supabase setup.');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleInitialize = async () => {
    setInitializing(true);
    setError('');
    try {
      const msg = await storageService.seedStudents();
      setSuccessMsg("System successfully initialized! You can now login with demo accounts.");
      setDbEmpty(false);
    } catch (err) {
      setError('Initialization failed. Verify table permissions.');
      console.error(err);
    } finally {
      setInitializing(false);
    }
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccessMsg('');

    if (regName && regUsn && regPass) {
      setLoading(true);
      try {
        const newUser = await storageService.registerStudent(regName.trim(), regUsn.trim(), regPass);
        onLogin(newUser);
      } catch (err: any) {
        setError(err.message || 'Registration failed.');
      } finally {
        setLoading(false);
      }
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 flex items-center justify-center p-4">
      {/* Background Decorative Elements */}
      <div className="absolute top-0 left-0 w-full h-1/2 bg-orange-600 -z-10 rounded-b-[40px] shadow-2xl"></div>

      <div className="bg-white rounded-[32px] shadow-2xl w-full max-w-md overflow-hidden z-10 border border-gray-100 flex flex-col">

        {/* Navigation Tabs */}
        <div className="flex bg-gray-50 p-2 rounded-t-[32px] m-4 mb-0">
          <button
            onClick={() => { setActiveTab('STUDENT'); setIsRegistering(false); setError(''); setSuccessMsg(''); setDbEmpty(false); }}
            className={`flex-1 py-3.5 text-sm font-bold flex items-center justify-center gap-2 rounded-2xl transition-all ${
              activeTab === 'STUDENT' ? 'bg-white text-orange-600 shadow-sm' : 'text-gray-500 hover:bg-gray-100/50'
            }`}
          >
            <GraduationCap className="w-4 h-4" /> Student
          </button>
          <button
            onClick={() => { setActiveTab('TEACHER'); setIsRegistering(false); setError(''); setSuccessMsg(''); setDbEmpty(false); }}
            className={`flex-1 py-3.5 text-sm font-bold flex items-center justify-center gap-2 rounded-2xl transition-all ${
              activeTab === 'TEACHER' ? 'bg-white text-orange-600 shadow-sm' : 'text-gray-500 hover:bg-gray-100/50'
            }`}
          >
            <Briefcase className="w-4 h-4" /> Faculty
          </button>
