  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccessMsg('');
    setShowInitOption(false);
    setLoading(true);

    try {
      const user = await storageService.login(identifier.trim(), password);

      if (user) {
        const isStudentTab = activeTab === 'STUDENT';
        const isTeacherTab = activeTab === 'TEACHER';
        const isStudentUser = user.role === 'STUDENT';
        const isStaffUser = user.role === 'TEACHER' || user.role === 'HOD';

        if (isStudentTab && isStudentUser) {
          onLogin(user);
        } else if (isTeacherTab && isStaffUser) {
          onLogin(user);
        } else {
          setError(`Found account, but please use the ${user.role === 'STUDENT' ? 'Student' : 'Faculty'} tab.`);
        }
      } else {
        // Login failed - could be wrong password OR empty DB
        const allUsers = await storageService.getUsers();
        if (allUsers.length === 0) {
             setError('System database is currently empty.');
             setShowInitOption(true);
        } else {
             setError('Invalid credentials. Check your username/password.');
        }
      }
    } catch (err) {
      setError('Connection error. Please check your Supabase configuration.');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleInitialize = async () => {
    setInitializing(true);
    setError('');
    try {
      await storageService.seedStudents();
      setSuccessMsg("System initialized! You can now login with USN or Faculty name.");
      setShowInitOption(false);
    } catch (err) {
      setError('Initialization failed. Check Supabase permissions/connection.');
