import { LeaveApplication, User } from '../types';
import { supabase } from './supabaseClient';
import { MOCK_STUDENTS, MOCK_TEACHER, MOCK_HOD, MOCK_JUNIOR_TEACHER } from '../constants';

export const storageService = {
  getUsers: async (): Promise<User[]> => {
    try {
      const { data, error } = await supabase.from('users').select('*');
      if (error) throw error;
      return (data as User[]) || [];
    } catch (error) {
      console.warn("Supabase getUsers error:", error);
      return [];
    }
  },

  getFaculty: async (): Promise<User[]> => {
    const { data, error } = await supabase
      .from('users')
      .select('*')
      .in('role', ['TEACHER', 'HOD']);
    if (error) throw error;
    return data as User[];
  },

  login: async (identifier: string, password: string, targetRole: 'STUDENT' | 'FACULTY'): Promise<User | null> => {
    const searchId = identifier.trim();
    if (!searchId) return null;

    try {
        // 1. Try finding user in Supabase with Role Filter
        let query = supabase.from('users').select('*');

        if (targetRole === 'STUDENT') {
            query = query.eq('role', 'STUDENT');
        } else {
            query = query.in('role', ['TEACHER', 'HOD']);
        }

        // Use a safe OR filter
        const { data, error } = await query.or(`name.ilike.%${searchId}%,usn.ilike.%${searchId}%`);

        if (!error && data && data.length > 0) {
            // Verify password (Case-Sensitive)
            const validUser = data.find(u => u.password === password);
            if (validUser) return validUser as User;
        }
    } catch (e) {
        console.error("Supabase login search failed:", e);
    }

    // 2. FALLBACK: Check Constants / Auto-Seed if not in DB yet
    const lowerSearch = searchId.toLowerCase();

    if (targetRole === 'FACULTY') {
        // Check HOD
        if ((MOCK_HOD.name.toLowerCase() === lowerSearch || lowerSearch === 'hod') && MOCK_HOD.password === password) {
            return await storageService.autoSeedUser(MOCK_HOD);
        }
        // Check Senior Teacher
        if ((MOCK_TEACHER.name.toLowerCase() === lowerSearch || lowerSearch === 'teacher') && MOCK_TEACHER.password === password) {
             return await storageService.autoSeedUser(MOCK_TEACHER);
        }
        // Check Junior Teacher
        if (MOCK_JUNIOR_TEACHER.name.toLowerCase() === lowerSearch && MOCK_JUNIOR_TEACHER.password === password) {
             return await storageService.autoSeedUser(MOCK_JUNIOR_TEACHER);
        }
    } else {
        // Check Students
        const mockStudent = MOCK_STUDENTS.find(s => 
            (s.usn?.toLowerCase() === lowerSearch || s.name.toLowerCase() === lowerSearch) && 
            s.password === password
        );
        if (mockStudent) {
            return await storageService.autoSeedUser(mockStudent);
        }
    }

    return null;
  },

  autoSeedUser: async (mockUser: User): Promise<User> => {
      // Check if already exists by USN or Name+Role
      let query = supabase.from('users').select('*').eq('role', mockUser.role);
      if (mockUser.usn) {
          query = query.eq('usn', mockUser.usn);
      } else {
          query = query.eq('name', mockUser.name);
      }

      const { data: existing } = await query.maybeSingle();
      if (existing) return existing as User;

      // Ensure canApprove is set correctly for teachers
      let canApprove = mockUser.canApprove;
      if (canApprove === undefined) {
          canApprove = mockUser.role === 'HOD';
      }

      const { data: newUser, error } = await supabase.from('users').insert([{
             name: mockUser.name,
             usn: mockUser.usn,
             role: mockUser.role,
             password: mockUser.password,
             canApprove: canApprove
        }]).select().single();

      if (error) {
          console.error("Auto-seed insertion failed:", error);
          throw error;
      }
      return newUser as User;
  },

  registerStudent: async (name: string, usn: string, password: string): Promise<User> => {
    const { data: existing } = await supabase
        .from('users')
        .select('id')
        .eq('role', 'STUDENT')
        .eq('usn', usn)
        .maybeSingle();

    if (existing) {
        throw new Error("A student with this USN is already registered.");
    }

    const newUser = {
      name,
      usn,
      password,
      role: 'STUDENT',
      profilePic: ''
    };

    const { data, error } = await supabase
      .from('users')
      .insert([newUser])
      .select()
      .single();

    if (error) throw error;
    return data as User;
  },

  updateUser: async (updatedUser: User): Promise<void> => {
    const { error } = await supabase
      .from('users')
      .update({ profilePic: updatedUser.profilePic })
      .eq('id', updatedUser.id);
    if (error) throw error;
  },

  updateFacultyPermission: async (userId: string, canApprove: boolean): Promise<void> => {
    const { error } = await supabase
      .from('users')
      .update({ canApprove })
      .eq('id', userId);
    if (error) throw error;
  },

  getApplications: async (): Promise<LeaveApplication[]> => {
    const { data, error } = await supabase
      .from('applications')
      .select('*');
    if (error) throw error;
    return (data as LeaveApplication[]) || [];
  },

  saveApplication: async (app: LeaveApplication): Promise<void> => {
    const { id, ...appData } = app;
    const { error } = await supabase
      .from('applications')
      .insert([appData]); 
    if (error) throw error;
  },

  updateApplicationStatus: async (id: string, status: 'APPROVED' | 'REJECTED' | 'PENDING'): Promise<void> => {
    const { error } = await supabase
      .from('applications')
      .update({ 
        status: status,
        reviewedAt: status === 'PENDING' ? null : new Date().toISOString()
      })
      .eq('id', id);
    if (error) throw error;
  },

  togglePriority: async (id: string, isPriority: boolean): Promise<void> => {
    const { error } = await supabase
      .from('applications')
      .update({ isPriority })
      .eq('id', id);
    if (error) throw error;
  },

  assignApplication: async (appId: string, teacherId: string | null): Promise<void> => {
    const { error } = await supabase
      .from('applications')
      .update({ assignedTeacherId: teacherId })
      .eq('id', appId);
    if (error) throw error;
  },

  seedStudents: async (): Promise<string> => {
    // Seed core faculty first
    await storageService.upsertUser(MOCK_HOD);
    await storageService.upsertUser(MOCK_TEACHER);
    await storageService.upsertUser(MOCK_JUNIOR_TEACHER);

    // Seed Students in batches
    const BATCH_SIZE = 10;
    for (let i = 0; i < MOCK_STUDENTS.length; i += BATCH_SIZE) {
        const batch = MOCK_STUDENTS.slice(i, i + BATCH_SIZE);
        await Promise.all(batch.map(s => storageService.upsertUser(s)));
    }

    return `System successfully initialized with all demo records.`;
  },

  upsertUser: async (user: Partial<User>) => {
      let query = supabase.from('users').select('id').eq('role', user.role);
      if (user.usn) {
          query = query.eq('usn', user.usn);
      } else if (user.name) {
          query = query.eq('name', user.name);
      }

      const { data: existing } = await query.maybeSingle();

      if (existing) {
          await supabase.from('users').update({ 
              password: user.password,
              canApprove: user.canApprove 
          }).eq('id', existing.id);
      } else {
          await supabase.from('users').insert([{
              name: user.name,
              usn: user.usn,
              role: user.role,
              password: user.password,
              canApprove: user.canApprove
          }]);
      }
  }
};

import React, { useState } from 'react';
import { storageService } from '../services/storageService';
import { User, Role } from '../types';
import { Button } from '../components/Button';
import { GraduationCap, Briefcase, UserPlus, Loader2, Database, ShieldAlert, CheckCircle2 } from 'lucide-react';

interface LoginProps {
  onLogin: (user: User) => void;
}

export const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [activeTab, setActiveTab] = useState<'STUDENT' | 'FACULTY'>('STUDENT');
  const [isRegistering, setIsRegistering] = useState(false);
  const [loading, setLoading] = useState(false);
  const [initializing, setInitializing] = useState(false);

  // Form State
  const [identifier, setIdentifier] = useState('');
  const [password, setPassword] = useState('');
  const [regName, setRegName] = useState('');
  const [regUsn, setRegUsn] = useState('');
  const [regPass, setRegPass] = useState('');
  const [error, setError] = useState('');
  const [successMsg, setSuccessMsg] = useState('');
  const [showInitOption, setShowInitOption] = useState(false);

  const inputClasses = "w-full px-4 py-3 bg-white border border-gray-200 rounded-xl focus:ring-2 focus:ring-orange-500 focus:border-transparent outline-none transition-all text-gray-900 placeholder-gray-400 shadow-sm font-medium";

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccessMsg('');
    setShowInitOption(false);
    setLoading(true);

    try {
      // Pass activeTab as targetRole to ensure we only find relevant users
      const user = await storageService.login(identifier.trim(), password, activeTab);

      if (user) {
        onLogin(user);
      } else {
        // Login failed - double check if database is actually empty
        const allUsers = await storageService.getUsers();
        if (allUsers.length === 0) {
             setError('System database is currently uninitialized.');
             setShowInitOption(true);
        } else {
             setError(`Invalid ${activeTab === 'STUDENT' ? 'USN/Password' : 'Faculty credentials'}. Please try again.`);
        }
      }
    } catch (err) {
      setError('Connection failed. Please check your network or Supabase keys.');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleInitialize = async () => {
    setInitializing(true);
    setError('');
    try {
      await storageService.seedStudents();
      setSuccessMsg("Database successfully initialized! You can now log in.");
      setShowInitOption(false);
    } catch (err) {
      setError('Initialization failed. Verify your Supabase table permissions.');
      console.error(err);
    } finally {
      setInitializing(false);
    }
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccessMsg('');

    if (regName && regUsn && regPass) {
      setLoading(true);
      try {
        const newUser = await storageService.registerStudent(regName.trim(), regUsn.trim(), regPass);
        onLogin(newUser);
      } catch (err: any) {
        setError(err.message || 'Registration failed.');
      } finally {
        setLoading(false);
      }
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 flex items-center justify-center p-4 relative overflow-hidden">
      {/* Dynamic Background */}
      <div className={`absolute top-0 left-0 w-full h-[60%] bg-gradient-to-br ${activeTab === 'STUDENT' ? 'from-orange-500 to-orange-700' : 'from-blue-600 to-blue-800'} -z-10 rounded-b-[60px] shadow-2xl transition-all duration-700`}></div>

      <div className="bg-white/95 backdrop-blur-md rounded-[32px] shadow-2xl w-full max-w-md overflow-hidden z-10 border border-white/20 flex flex-col">

        {/* Navigation Tabs */}
        <div className="flex bg-gray-100/50 p-2 rounded-t-[32px] m-4 mb-0">
          <button
            onClick={() => { setActiveTab('STUDENT'); setIsRegistering(false); setError(''); setSuccessMsg(''); setShowInitOption(false); }}
            className={`flex-1 py-3.5 text-sm font-bold flex items-center justify-center gap-2 rounded-2xl transition-all ${
              activeTab === 'STUDENT' ? 'bg-white text-orange-600 shadow-lg' : 'text-gray-500 hover:bg-gray-100/80'
            }`}
          >
            <GraduationCap className="w-4 h-4" /> Student
          </button>
          <button
            onClick={() => { setActiveTab('FACULTY'); setIsRegistering(false); setError(''); setSuccessMsg(''); setShowInitOption(false); }}
            className={`flex-1 py-3.5 text-sm font-bold flex items-center justify-center gap-2 rounded-2xl transition-all ${
              activeTab === 'FACULTY' ? 'bg-white text-blue-600 shadow-lg' : 'text-gray-500 hover:bg-gray-100/80'
            }`}
          >
            <Briefcase className="w-4 h-4" /> Faculty
          </button>
        </div>

        <div className="p-8 pt-6">
          <div className="mb-8 text-center sm:text-left">
            <h1 className="text-3xl font-extrabold text-gray-900 tracking-tight">
              {activeTab === 'STUDENT' ? (isRegistering ? 'Join UniEvent' : 'Welcome back') : 'Staff Portal'}
            </h1>
            <p className="text-gray-500 text-sm mt-1.5 font-medium">
              {activeTab === 'STUDENT' 
                ? (isRegistering ? 'Fill in your details to get started' : 'Sign in to your student dashboard') 
                : 'Enter your credentials to manage applications'}
            </p>
          </div>

          {error && (
            <div className="bg-red-50 text-red-600 text-sm p-4 rounded-2xl mb-6 border border-red-100 animate-fade-in flex flex-col gap-3">
              <div className="flex items-center gap-2 font-bold">
                <ShieldAlert className="w-4 h-4" />
                <span>{error}</span>
              </div>
              {showInitOption && (
                <button 
                  onClick={handleInitialize}
                  disabled={initializing}
                  className="flex items-center justify-center gap-2 bg-red-600 text-white px-4 py-2.5 rounded-xl text-xs font-bold hover:bg-red-700 transition-all shadow-md active:scale-95 disabled:opacity-50"
                >
                  {initializing ? <Loader2 className="w-3 h-3 animate-spin" /> : <Database className="w-3 h-3" />}
                  Initialize Demo Database
                </button>
              )}
            </div>
          )}

          {successMsg && (
            <div className="bg-green-50 text-green-700 text-sm p-4 rounded-2xl mb-6 border border-green-100 animate-fade-in font-bold flex items-center gap-2">
              <CheckCircle2 className="w-4 h-4" />
              {successMsg}
            </div>
          )}

          {activeTab === 'STUDENT' && isRegistering ? (
            <form onSubmit={handleRegister} className="space-y-4">
               <div>
                <label className="block text-[10px] font-bold uppercase tracking-widest text-gray-400 mb-1.5 ml-1">Full Name</label>
                <input
                  type="text"
                  required
                  placeholder="John Doe"
                  className={inputClasses}
                  value={regName}
                  onChange={(e) => setRegName(e.target.value)}
                  disabled={loading || initializing}
                />
              </div>
              <div>
                <label className="block text-[10px] font-bold uppercase tracking-widest text-gray-400 mb-1.5 ml-1">University USN</label>
                <input
                  type="text"
                  required
                  placeholder="4PA24IC000"
                  className={inputClasses}
                  value={regUsn}
                  onChange={(e) => setRegUsn(e.target.value)}
                  disabled={loading || initializing}
                />
              </div>
              <div>
                <label className="block text-[10px] font-bold uppercase tracking-widest text-gray-400 mb-1.5 ml-1">Password</label>
                <input
                  type="password"
                  required
                  placeholder="••••••••"
                  className={inputClasses}
                  value={regPass}
                  onChange={(e) => setRegPass(e.target.value)}
                  disabled={loading || initializing}
                />
              </div>
              <Button type="submit" fullWidth disabled={loading || initializing} size="lg" className="rounded-2xl py-4 shadow-xl shadow-orange-100 mt-2">
                 {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : 'Create Account'}
              </Button>
              <div className="text-center mt-6">
                <button type="button" onClick={() => setIsRegistering(false)} className="text-sm text-gray-500 font-semibold hover:text-orange-600 transition-colors" disabled={loading || initializing}>
                  Have an account? <span className="text-orange-600 underline underline-offset-4 font-bold">Sign In</span>
                </button>
              </div>
            </form>
          ) : (
            <form onSubmit={handleLogin} className="space-y-4">
              <div>
                <label className="block text-[10px] font-bold uppercase tracking-widest text-gray-400 mb-1.5 ml-1">
                  {activeTab === 'STUDENT' ? 'USN / Student Name' : 'Faculty Name / ID'}
                </label>
                <input
                  type="text"
                  required
                  placeholder={activeTab === 'STUDENT' ? 'USN or Name' : 'Enter Faculty Name'}
                  className={inputClasses}
                  value={identifier}
                  onChange={(e) => setIdentifier(e.target.value)}
                  disabled={loading || initializing}
                />
              </div>
              <div>
                <label className="block text-[10px] font-bold uppercase tracking-widest text-gray-400 mb-1.5 ml-1">Password</label>
                <input
                  type="password"
                  required
                  placeholder="••••••••"
                  className={inputClasses}
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  disabled={loading || initializing}
                />
              </div>

              <Button 
                type="submit" 
                fullWidth 
                disabled={loading || initializing} 
                size="lg" 
                className={`rounded-2xl py-4 shadow-xl mt-2 transition-all ${activeTab === 'STUDENT' ? 'bg-orange-600 hover:bg-orange-700 shadow-orange-100' : 'bg-blue-600 hover:bg-blue-700 shadow-blue-100'}`}
              >
                {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : 'Sign In'}
              </Button>

              {activeTab === 'STUDENT' && (
                <div className="text-center mt-6">
                  <button type="button" onClick={() => setIsRegistering(true)} className="text-sm text-gray-500 font-semibold hover:text-orange-600 transition-colors inline-flex items-center gap-1.5" disabled={loading || initializing}>
                    Not registered yet? <span className="text-orange-600 underline underline-offset-4 font-bold">Join now</span>
                  </button>
                </div>
              )}
            </form>
          )}
        </div>
      </div>

      {/* Version Tag */}
      <div className="absolute bottom-4 text-[10px] font-bold text-gray-400 uppercase tracking-widest">
        UniEvent Secure Portal
      </div>
    </div>
  );
};

import { LeaveApplication, User } from '../types';
import { supabase } from './supabaseClient';
import { MOCK_STUDENTS, MOCK_TEACHER, MOCK_HOD, MOCK_JUNIOR_TEACHER } from '../constants';

export const storageService = {
  getUsers: async (): Promise<User[]> => {
    try {
      const { data, error } = await supabase.from('users').select('*');
      if (error) throw error;
      return (data as User[]) || [];
    } catch (error) {
      console.warn("Supabase getUsers error:", error);
      return [];
    }
  },

  getFaculty: async (): Promise<User[]> => {
    const { data, error } = await supabase
      .from('users')
      .select('*')
      .in('role', ['TEACHER', 'HOD']);
    if (error) throw error;
    return data as User[];
  },

  login: async (identifier: string, password: string, targetRole: 'STUDENT' | 'FACULTY'): Promise<User | null> => {
    const searchId = identifier.trim();
    if (!searchId) return null;

    try {
        let query = supabase.from('users').select('*');
        if (targetRole === 'STUDENT') {
            query = query.eq('role', 'STUDENT');
        } else {
            query = query.in('role', ['TEACHER', 'HOD']);
        }

        const { data, error } = await query.or(`name.ilike.%${searchId}%,usn.ilike.%${searchId}%`);

        if (!error && data && data.length > 0) {
            const validUser = data.find(u => u.password === password);
            if (validUser) return validUser as User;
        }
    } catch (e) {
        console.error("Supabase login search failed:", e);
    }

    const lowerSearch = searchId.toLowerCase();
    if (targetRole === 'FACULTY') {
        if ((MOCK_HOD.name.toLowerCase() === lowerSearch || lowerSearch === 'hod') && MOCK_HOD.password === password) {
            return await storageService.autoSeedUser(MOCK_HOD);
        }
        if ((MOCK_TEACHER.name.toLowerCase() === lowerSearch || lowerSearch === 'teacher') && MOCK_TEACHER.password === password) {
             return await storageService.autoSeedUser(MOCK_TEACHER);
        }
        if (MOCK_JUNIOR_TEACHER.name.toLowerCase() === lowerSearch && MOCK_JUNIOR_TEACHER.password === password) {
             return await storageService.autoSeedUser(MOCK_JUNIOR_TEACHER);
        }
    } else {
        const mockStudent = MOCK_STUDENTS.find(s => 
            (s.usn?.toLowerCase() === lowerSearch || s.name.toLowerCase() === lowerSearch) && 
            s.password === password
        );
        if (mockStudent) {
            return await storageService.autoSeedUser(mockStudent);
        }
    }
    return null;
  },

  autoSeedUser: async (mockUser: User): Promise<User> => {
      let query = supabase.from('users').select('*').eq('role', mockUser.role);
      if (mockUser.usn) {
          query = query.eq('usn', mockUser.usn);
      } else {
          query = query.eq('name', mockUser.name);
      }

      const { data: existing } = await query.maybeSingle();
      if (existing) return existing as User;

      let canApprove = mockUser.canApprove;
      if (canApprove === undefined) {
          canApprove = mockUser.role === 'HOD';
      }

      const { data: newUser, error } = await supabase.from('users').insert([{
             name: mockUser.name,
             usn: mockUser.usn,
             role: mockUser.role,
             password: mockUser.password,
             canApprove: canApprove
        }]).select().single();

      if (error) throw error;
      return newUser as User;
  },

  registerStudent: async (name: string, usn: string, password: string): Promise<User> => {
    const { data: existing } = await supabase
        .from('users')
        .select('id')
        .eq('role', 'STUDENT')
        .eq('usn', usn)
        .maybeSingle();

    if (existing) {
        throw new Error("A student with this USN is already registered.");
    }

    const newUser = {
      name,
      usn,
      password,
      role: 'STUDENT',
      profilePic: ''
    };

    const { data, error } = await supabase
      .from('users')
      .insert([newUser])
      .select()
      .single();

    if (error) throw error;
    return data as User;
  },

  updateUser: async (updatedUser: User): Promise<void> => {
    const { error } = await supabase
      .from('users')
      .update({ profilePic: updatedUser.profilePic })
      .eq('id', updatedUser.id);
    if (error) throw error;
  },

  updateFacultyPermission: async (userId: string, canApprove: boolean): Promise<void> => {
    const { error } = await supabase
      .from('users')
      .update({ canApprove })
      .eq('id', userId);
    if (error) throw error;
  },

  getApplications: async (): Promise<LeaveApplication[]> => {
    // Explicitly select all and order by newest to ensure fresh data
    const { data, error } = await supabase
      .from('applications')
      .select('*')
      .order('timestamp', { ascending: false });

    if (error) throw error;
    return (data as LeaveApplication[]) || [];
  },

  saveApplication: async (app: LeaveApplication): Promise<void> => {
    // Ensure id is unique if generated client-side, but standard practice is letting DB generate it.
    // However, for consistency, we'll keep the client-generated ID but wrap in array.
    const { error } = await supabase
      .from('applications')
      .insert([app]); 
    if (error) throw error;
  },

  updateApplicationStatus: async (id: string, status: 'APPROVED' | 'REJECTED' | 'PENDING'): Promise<void> => {
    const { error } = await supabase
      .from('applications')
      .update({ 
        status: status,
        reviewedAt: status === 'PENDING' ? null : new Date().toISOString()
      })
      .eq('id', id);
    if (error) throw error;
  },

  togglePriority: async (id: string, isPriority: boolean): Promise<void> => {
    const { error } = await supabase
      .from('applications')
      .update({ isPriority })
      .eq('id', id);
    if (error) throw error;
  },

  assignApplication: async (appId: string, teacherId: string | null): Promise<void> => {
    const { error } = await supabase
      .from('applications')
      .update({ assignedTeacherId: teacherId })
      .eq('id', appId);
    if (error) throw error;
  },

  seedStudents: async (): Promise<string> => {
    await storageService.upsertUser(MOCK_HOD);
    await storageService.upsertUser(MOCK_TEACHER);
    await storageService.upsertUser(MOCK_JUNIOR_TEACHER);

    const BATCH_SIZE = 10;
    for (let i = 0; i < MOCK_STUDENTS.length; i += BATCH_SIZE) {
        const batch = MOCK_STUDENTS.slice(i, i + BATCH_SIZE);
        await Promise.all(batch.map(s => storageService.upsertUser(s)));
    }
    return `System successfully initialized with all demo records.`;
  },

  upsertUser: async (user: Partial<User>) => {
      let query = supabase.from('users').select('id').eq('role', user.role);
      if (user.usn) {
          query = query.eq('usn', user.usn);
      } else if (user.name) {
          query = query.eq('name', user.name);
      }
      const { data: existing } = await query.maybeSingle();
      if (existing) {
          await supabase.from('users').update({ 
              password: user.password,
              canApprove: user.canApprove 
          }).eq('id', existing.id);
      } else {
          await supabase.from('users').insert([{
              name: user.name,
              usn: user.usn,
              role: user.role,
              password: user.password,
              canApprove: user.canApprove
          }]);
      }
  }
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
