import { LeaveApplication, User } from '../types';
import { supabase } from './supabaseClient';
import { MOCK_STUDENTS, MOCK_TEACHER, MOCK_HOD, MOCK_JUNIOR_TEACHER } from '../constants';

export const storageService = {
  // SQL Schema for the user to copy-paste into Supabase SQL Editor
  REQUIRED_SQL: `
-- 1. Create Users Table
CREATE TABLE IF NOT EXISTS public.users (
    id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
    name text NOT NULL,
    usn text UNIQUE,
    role text NOT NULL CHECK (role IN ('STUDENT', 'TEACHER', 'HOD')),
    password text NOT NULL,
    "profilePic" text,
    "canApprove" boolean DEFAULT false
);

-- 2. Create Applications Table
CREATE TABLE IF NOT EXISTS public.applications (
    id text PRIMARY KEY,
    "studentId" text NOT NULL,
    "studentName" text NOT NULL,
    "studentUSN" text NOT NULL,
    "studentProfilePic" text,
    "eventName" text NOT NULL,
    "startDate" date NOT NULL,
    "endDate" date NOT NULL,
    reason text NOT NULL,
    status text NOT NULL DEFAULT 'PENDING',
    "timestamp" timestamptz DEFAULT now(),
    "reviewedAt" timestamptz,
    "imageUrl" text,
    "isPriority" boolean DEFAULT false,
    "assignedTeacherId" text
);

-- 3. Enable Public Access (Rls can be configured later)
ALTER TABLE public.users ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.applications ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Allow public access" ON public.users FOR ALL USING (true);
CREATE POLICY "Allow public access" ON public.applications FOR ALL USING (true);
  `,

  checkDatabaseConnection: async (): Promise<{ ok: boolean; error?: string }> => {
    try {
      // Try to select from both tables to check existence
      const userCheck = await supabase.from('users').select('id').limit(1);
      if (userCheck.error && userCheck.error.code === 'PGRST205') {
        return { ok: false, error: 'Table "users" is missing' };
      }

      const appCheck = await supabase.from('applications').select('id').limit(1);
      if (appCheck.error && appCheck.error.code === 'PGRST205') {
        return { ok: false, error: 'Table "applications" is missing' };
      }

      return { ok: true };
    } catch (e) {
      return { ok: false, error: 'Connection failed' };
    }
  },

  getUsers: async (): Promise<User[]> => {
    try {
      const { data, error } = await supabase.from('users').select('*');
      if (error) throw error;
      return (data as User[]) || [];
    } catch (error) {
      console.warn("Supabase getUsers error:", error);
      return [];
    }
  },

  getFaculty: async (): Promise<User[]> => {
    const { data, error } = await supabase
      .from('users')
      .select('*')
      .in('role', ['TEACHER', 'HOD']);
    if (error) throw error;
    return data as User[];
  },

  login: async (identifier: string, password: string, targetRole: 'STUDENT' | 'FACULTY'): Promise<User | null> => {
    const searchId = identifier.trim();
    if (!searchId) return null;

    try {
        let query = supabase.from('users').select('*');
        if (targetRole === 'STUDENT') {
            query = query.eq('role', 'STUDENT');
        } else {
            query = query.in('role', ['TEACHER', 'HOD']);
        }

        const { data, error } = await query.or(`name.ilike.%${searchId}%,usn.ilike.%${searchId}%`);

        if (!error && data && data.length > 0) {
            const validUser = data.find(u => u.password === password);
            if (validUser) return validUser as User;
        }
    } catch (e) {
        console.error("Supabase login search failed:", e);
    }

    const lowerSearch = searchId.toLowerCase();
    if (targetRole === 'FACULTY') {
        if ((MOCK_HOD.name.toLowerCase() === lowerSearch || lowerSearch === 'hod') && MOCK_HOD.password === password) {
            return await storageService.autoSeedUser(MOCK_HOD);
        }
        if ((MOCK_TEACHER.name.toLowerCase() === lowerSearch || lowerSearch === 'teacher') && MOCK_TEACHER.password === password) {
             return await storageService.autoSeedUser(MOCK_TEACHER);
        }
        if (MOCK_JUNIOR_TEACHER.name.toLowerCase() === lowerSearch && MOCK_JUNIOR_TEACHER.password === password) {
             return await storageService.autoSeedUser(MOCK_JUNIOR_TEACHER);
        }
    } else {
        const mockStudent = MOCK_STUDENTS.find(s => 
            (s.usn?.toLowerCase() === lowerSearch || s.name.toLowerCase() === lowerSearch) && 
            s.password === password
        );
        if (mockStudent) {
            return await storageService.autoSeedUser(mockStudent);
        }
    }
    return null;
  },

  autoSeedUser: async (mockUser: User): Promise<User> => {
      let query = supabase.from('users').select('*').eq('role', mockUser.role);
      if (mockUser.usn) {
          query = query.eq('usn', mockUser.usn);
      } else {
          query = query.eq('name', mockUser.name);
      }

      const { data: existing } = await query.maybeSingle();
      if (existing) return existing as User;

      let canApprove = mockUser.canApprove;
      if (canApprove === undefined) {
          canApprove = mockUser.role === 'HOD';
      }

      const { data: newUser, error } = await supabase.from('users').insert([{
             name: mockUser.name,
             usn: mockUser.usn,
             role: mockUser.role,
             password: mockUser.password,
             canApprove: canApprove
        }]).select().single();

      if (error) throw error;
      return newUser as User;
  },

  registerStudent: async (name: string, usn: string, password: string): Promise<User> => {
    const { data: existing } = await supabase
        .from('users')
        .select('id')
        .eq('role', 'STUDENT')
        .eq('usn', usn)
        .maybeSingle();

    if (existing) {
        throw new Error("A student with this USN is already registered.");
    }

    const newUser = {
      name,
      usn,
      password,
      role: 'STUDENT',
      profilePic: ''
    };

    const { data, error } = await supabase
      .from('users')
      .insert([newUser])
      .select()
      .single();

    if (error) throw error;
    return data as User;
  },

  updateUser: async (updatedUser: User): Promise<void> => {
    const { error } = await supabase
      .from('users')
      .update({ profilePic: updatedUser.profilePic })
      .eq('id', updatedUser.id);
    if (error) throw error;
  },

  updateFacultyPermission: async (userId: string, canApprove: boolean): Promise<void> => {
    const { error } = await supabase
      .from('users')
      .update({ canApprove })
      .eq('id', userId);
    if (error) throw error;
  },

  getApplications: async (): Promise<LeaveApplication[]> => {
    const { data, error } = await supabase
      .from('applications')
      .select('*')
      .order('timestamp', { ascending: false });

    if (error) throw error;
    return (data as LeaveApplication[]) || [];
  },

  saveApplication: async (app: LeaveApplication): Promise<void> => {
    const { error } = await supabase
      .from('applications')
      .insert([app]); 
    if (error) throw error;
  },

  updateApplicationStatus: async (id: string, status: 'APPROVED' | 'REJECTED' | 'PENDING'): Promise<void> => {
    const { error } = await supabase
      .from('applications')
      .update({ 
        status: status,
        reviewedAt: status === 'PENDING' ? null : new Date().toISOString()
      })
      .eq('id', id);
    if (error) throw error;
  },

  togglePriority: async (id: string, isPriority: boolean): Promise<void> => {
    const { error } = await supabase
      .from('applications')
      .update({ isPriority })
      .eq('id', id);
    if (error) throw error;
  },

  assignApplication: async (appId: string, teacherId: string | null): Promise<void> => {
    const { error } = await supabase
      .from('applications')
      .update({ assignedTeacherId: teacherId })
      .eq('id', appId);
    if (error) throw error;
  },

  seedStudents: async (): Promise<string> => {
    await storageService.upsertUser(MOCK_HOD);
    await storageService.upsertUser(MOCK_TEACHER);
    await storageService.upsertUser(MOCK_JUNIOR_TEACHER);

    const BATCH_SIZE = 10;
    for (let i = 0; i < MOCK_STUDENTS.length; i += BATCH_SIZE) {
        const batch = MOCK_STUDENTS.slice(i, i + BATCH_SIZE);
        await Promise.all(batch.map(s => storageService.upsertUser(s)));
    }
    return `System successfully initialized with all demo records.`;
  },

  upsertUser: async (user: Partial<User>) => {
      let query = supabase.from('users').select('id').eq('role', user.role);
      if (user.usn) {
          query = query.eq('usn', user.usn);
      } else if (user.name) {
          query = query.eq('name', user.name);
      }
      const { data: existing } = await query.maybeSingle();
      if (existing) {
          await supabase.from('users').update({ 
              password: user.password,
              canApprove: user.canApprove 
          }).eq('id', existing.id);
      } else {
          await supabase.from('users').insert([{
              name: user.name,
              usn: user.usn,
              role: user.role,
              password: user.password,
              canApprove: user.canApprove
          }]);
      }
  }
};

import React, { useState, useEffect } from 'react';
import { Login } from './pages/Login';
import { StudentDashboard } from './pages/StudentDashboard';
import { TeacherDashboard } from './pages/TeacherDashboard';
import { User } from './types';
import { storageService } from './services/storageService';
import { isSupabaseConfigured } from './services/supabaseClient';
import { Database, AlertTriangle, Terminal, CheckCircle, Copy } from 'lucide-react';

function App() {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isConfigured, setIsConfigured] = useState(true);
  const [isSchemaMissing, setIsSchemaMissing] = useState(false);
  const [copying, setCopying] = useState(false);

  // Check session and configuration on mount
  useEffect(() => {
    if (!isSupabaseConfigured()) {
      setIsConfigured(false);
      setIsLoading(false);
      return;
    }

    const startupCheck = async () => {
      try {
        // 1. Check for table existence
        const dbStatus = await storageService.checkDatabaseConnection();
        if (!dbStatus.ok) {
           setIsSchemaMissing(true);
           setIsLoading(false);
           return;
        }

        // 2. Check for existing session
        const session = localStorage.getItem('unievent_session');
        if (session) {
          setUser(JSON.parse(session));
        }
      } catch (err) {
        console.error("Startup check failed", err);
      } finally {
        setIsLoading(false);
      }
    };
    startupCheck();
  }, []);

  const handleLogin = (loggedInUser: User) => {
    setUser(loggedInUser);
    localStorage.setItem('unievent_session', JSON.stringify(loggedInUser));
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('unievent_session');
  };

  const copySql = () => {
    navigator.clipboard.writeText(storageService.REQUIRED_SQL);
    setCopying(true);
    setTimeout(() => setCopying(false), 2000);
  };

  // Schema Setup Screen (Shown if tables applications or users are missing)
  if (isSchemaMissing) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50 p-4 font-sans">
        <div className="max-w-2xl w-full bg-white rounded-3xl shadow-2xl overflow-hidden border border-gray-100">
           <div className="bg-red-600 p-8 text-white text-center">
              <Database className="w-16 h-16 mx-auto mb-4 opacity-90" />
              <h1 className="text-3xl font-extrabold mb-2">Tables Missing</h1>
              <p className="opacity-90 max-w-md mx-auto">
                UniEvent requires specific database tables to function. We couldn't find "users" or "applications" in your Supabase project.
              </p>
           </div>

           <div className="p-8">
              <div className="space-y-6">
                 <div>
                    <h2 className="flex items-center gap-2 text-lg font-bold text-gray-900 mb-4">
                       <Terminal className="w-5 h-5 text-red-600" />
                       Fix: Run this SQL in Supabase
                    </h2>
                    <div className="relative">
                       <pre className="bg-gray-900 text-green-400 p-6 rounded-2xl overflow-x-auto text-xs font-mono max-h-64 border-4 border-gray-800">
                          {storageService.REQUIRED_SQL}
                       </pre>
                       <button 
                          onClick={copySql}
                          className="absolute top-4 right-4 bg-white/10 hover:bg-white/20 text-white px-3 py-1.5 rounded-lg text-xs font-bold transition-all backdrop-blur-md flex items-center gap-2"
                       >
                          {copying ? <CheckCircle className="w-3.5 h-3.5" /> : <Copy className="w-3.5 h-3.5" />}
                          {copying ? 'Copied!' : 'Copy SQL'}
                       </button>
                    </div>
                 </div>

                 <div className="bg-blue-50 border border-blue-100 rounded-2xl p-5 flex gap-4">
                    <div className="w-10 h-10 bg-blue-100 rounded-full flex items-center justify-center shrink-0">
                       <span className="text-blue-600 font-bold">!</span>
                    </div>
                    <div>
                       <h3 className="font-bold text-blue-900 mb-1">How to setup:</h3>
                       <ol className="text-sm text-blue-800 list-decimal list-inside space-y-1 opacity-80">
                          <li>Go to your <b>Supabase Dashboard</b></li>
                          <li>Open the <b>SQL Editor</b> from the sidebar</li>
                          <li>Click <b>New Query</b> and paste the code above</li>
                          <li>Click <b>Run</b>, then come back here and refresh</li>
                       </ol>
                    </div>
                 </div>

                 <button 
                    onClick={() => window.location.reload()} 
                    className="w-full bg-gray-900 text-white font-bold py-4 rounded-2xl hover:bg-black transition-all shadow-xl active:scale-[0.98]"
                 >
                    I've executed the SQL. Refresh App.
                 </button>
              </div>
           </div>
        </div>
      </div>
    );
  }

  // Config Missing Screen
  if (!isConfigured) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50 p-4">
        <div className="max-w-md w-full bg-white rounded-2xl shadow-xl p-8 border border-orange-100 text-center">
          <div className="w-16 h-16 bg-orange-100 text-orange-600 rounded-full flex items-center justify-center mx-auto mb-6">
            <Database className="w-8 h-8" />
          </div>
          <h1 className="text-2xl font-bold text-gray-900 mb-2">Connect Database</h1>
          <p className="text-gray-600 mb-6">
            To use UniEvent, you need to connect your Supabase database.
          </p>

          <div className="bg-yellow-50 border border-yellow-200 rounded-lg p-4 text-left mb-6">
            <div className="flex gap-2 text-yellow-800 font-semibold mb-2 items-center">
              <AlertTriangle className="w-4 h-4" /> Action Required
            </div>
            <p className="text-sm text-yellow-700 mb-2">
              Open <code className="bg-yellow-100 px-1 py-0.5 rounded font-mono text-yellow-900">services/supabaseClient.ts</code>
            </p>
            <ol className="list-decimal list-inside text-sm text-yellow-700 space-y-1">
              <li>Paste your <b>Project URL</b></li>
              <li>Paste your <b>Anon Key</b></li>
