    const newUser = {
      name,
      usn,
      password,
      role: 'STUDENT',
      profilePic: ''
    };

    const { data, error } = await supabase
      .from('users')
      .insert([newUser])
      .select()
      .single();

    if (error) throw error;
    return data as User;
  },

  // Update user profile information
  updateUser: async (updatedUser: User): Promise<void> => {
    const { error } = await supabase
      .from('users')
      .update({
        name: updatedUser.name,
        profilePic: updatedUser.profilePic,
        canApprove: updatedUser.canApprove
      })
      .eq('id', updatedUser.id);
    if (error) throw error;
  },

  // Seed the database with initial mock students
  seedStudents: async (): Promise<void> => {
    const studentsToSeed = MOCK_STUDENTS.map(s => ({
      name: s.name,
      usn: s.usn,
      role: s.role,
      password: s.password,
      canApprove: false
    }));

    const { error } = await supabase.from('users').upsert(studentsToSeed, { onConflict: 'usn' });
    if (error) throw error;
  },

  // Retrieve all leave applications from the database
  getApplications: async (): Promise<LeaveApplication[]> => {
    const { data, error } = await supabase.from('applications').select('*');
    if (error) throw error;
    return (data as LeaveApplication[]) || [];
  },

  // Persist a new leave application to the database
  saveApplication: async (app: LeaveApplication): Promise<void> => {
    const { error } = await supabase.from('applications').insert([app]);
    if (error) throw error;
  },

