                {filteredApplications.map((app) => (
                <div key={app.id} className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden hover:shadow-md transition-shadow group"><div className="flex flex-col sm:flex-row"><div className="sm:w-48 h-32 sm:h-auto bg-gray-100 relative shrink-0">{app.imageUrl ? <img src={app.imageUrl} alt={app.eventName} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center bg-gray-50 text-gray-300"><ImageIcon className="w-8 h-8" /></div>}<div className="absolute top-2 left-2 sm:hidden">{getStatusBadge(app.status)}</div></div><div className="flex-1 p-5 flex flex-col justify-between"><div><div className="flex justify-between items-start mb-2"><div><h3 className="font-bold text-lg text-gray-900 leading-tight">{app.eventName}</h3><div className="flex items-center gap-2 text-gray-500 text-xs mt-1"><Calendar className="w-3 h-3"/><span className="font-medium">{format(new Date(app.startDate), 'MMM d, yyyy')}</span><ArrowRight className="w-3 h-3" /><span className="font-medium">{format(new Date(app.endDate), 'MMM d, yyyy')}</span></div></div><div className="hidden sm:block">{getStatusBadge(app.status)}</div></div><p className="text-gray-600 text-sm line-clamp-2 mb-4 bg-gray-50 p-2 rounded border border-gray-100/50">{app.reason}</p></div><div className="flex items-center justify-between pt-3 border-t border-gray-50"><div className="text-xs text-gray-400">Applied {format(new Date(app.timestamp), 'MMM d')}</div>{app.status === 'APPROVED' && isFuture(new Date(app.startDate)) && <span className="text-xs font-bold text-orange-600 bg-orange-50 px-2 py-1 rounded flex items-center gap-1"><Hourglass className="w-3 h-3" /> Upcoming</span>}</div></div></div></div>))}
            </div>
            </section>
        </div>
      </main>
    </div>
  );
};

import { LeaveApplication, User } from '../types';
import { supabase } from './supabaseClient';
import { MOCK_STUDENTS, MOCK_TEACHER, MOCK_HOD, MOCK_JUNIOR_TEACHER } from '../constants';

export const storageService = {
  // SQL Schema for the user to copy-paste into Supabase SQL Editor
  REQUIRED_SQL: `
-- 1. Create Users Table
CREATE TABLE IF NOT EXISTS public.users (
    id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
    name text NOT NULL,
    usn text UNIQUE,
    role text NOT NULL CHECK (role IN ('STUDENT', 'TEACHER', 'HOD')),
    password text NOT NULL,
    "profilePic" text,
    "canApprove" boolean DEFAULT false
);

-- 2. Create Applications Table
CREATE TABLE IF NOT EXISTS public.applications (
    id text PRIMARY KEY,
    "studentId" text NOT NULL,
    "studentName" text NOT NULL,
    "studentUSN" text NOT NULL,
    "studentProfilePic" text,
    "eventName" text NOT NULL,
    "startDate" date NOT NULL,
    "endDate" date NOT NULL,
    reason text NOT NULL,
    status text NOT NULL DEFAULT 'PENDING',
    "timestamp" timestamptz DEFAULT now(),
    "reviewedAt" timestamptz,
    "imageUrl" text,
    "isPriority" boolean DEFAULT false,
    "assignedTeacherId" text
);

-- 3. Enable Public Access (Robust RLS Policies)
-- This allows the app to function for demo purposes without auth setup
ALTER TABLE public.users ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.applications ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Allow public access users" ON public.users;
DROP POLICY IF EXISTS "Allow public access apps" ON public.applications;

CREATE POLICY "Allow public access users" ON public.users 
FOR ALL USING (true) WITH CHECK (true);

CREATE POLICY "Allow public access apps" ON public.applications 
FOR ALL USING (true) WITH CHECK (true);
  `,

  checkDatabaseConnection: async (): Promise<{ ok: boolean; error?: string; code?: string }> => {
    try {
      // Check for users table
      const { error: userError } = await supabase.from('users').select('id').limit(1);
      if (userError) {
        return { ok: false, error: userError.message, code: userError.code };
      }

      // Check for applications table
      const { error: appError } = await supabase.from('applications').select('id').limit(1);
      if (appError) {
        return { ok: false, error: appError.message, code: appError.code };
      }

      return { ok: true };
    } catch (e: any) {
      return { ok: false, error: 'Database connection failed', code: 'CONNECTION_ERROR' };
    }
  },

  getUsers: async (): Promise<User[]> => {
    const { data, error } = await supabase.from('users').select('*');
    if (error) throw error;
    return (data as User[]) || [];
  },

  getFaculty: async (): Promise<User[]> => {
    const { data, error } = await supabase
      .from('users')
      .select('*')
      .in('role', ['TEACHER', 'HOD']);
    if (error) throw error;
    return data as User[];
  },

  login: async (identifier: string, password: string, targetRole: 'STUDENT' | 'FACULTY'): Promise<User | null> => {
    const searchId = identifier.trim();
    if (!searchId) return null;

    try {
        const { data: anyUser } = await supabase.from('users')
          .select('role')
          .or(`name.ilike.%${searchId}%,usn.ilike.%${searchId}%`)
          .maybeSingle();

        if (anyUser) {
          const isActuallyFaculty = anyUser.role === 'TEACHER' || anyUser.role === 'HOD';
          const wantsStudent = targetRole === 'STUDENT';

          if (wantsStudent && isActuallyFaculty) {
            throw new Error("This is a Faculty account. Please use the Faculty tab.");
          }
          if (!wantsStudent && !isActuallyFaculty) {
            throw new Error("This is a Student account. Please use the Student tab.");
          }
        }

        let query = supabase.from('users').select('*');
        if (targetRole === 'STUDENT') {
            query = query.eq('role', 'STUDENT');
        } else {
            query = query.in('role', ['TEACHER', 'HOD']);
        }

        const { data, error } = await query.or(`name.ilike.%${searchId}%,usn.ilike.%${searchId}%`);

        if (!error && data && data.length > 0) {
            const validUser = data.find(u => u.password === password);
            if (validUser) return validUser as User;
        }
    } catch (e: any) {
        if (e.message && e.message.includes("tab")) throw e;
        console.error("Supabase login search failed:", e);
    }

    const lowerSearch = searchId.toLowerCase();
    if (targetRole === 'FACULTY') {
        if ((MOCK_HOD.name.toLowerCase() === lowerSearch || lowerSearch === 'hod') && MOCK_HOD.password === password) {
            return await storageService.autoSeedUser(MOCK_HOD);
        }
        if ((MOCK_TEACHER.name.toLowerCase() === lowerSearch || lowerSearch === 'teacher') && MOCK_TEACHER.password === password) {
             return await storageService.autoSeedUser(MOCK_TEACHER);
        }
        if (MOCK_JUNIOR_TEACHER.name.toLowerCase() === lowerSearch && MOCK_JUNIOR_TEACHER.password === password) {
             return await storageService.autoSeedUser(MOCK_JUNIOR_TEACHER);
        }
    } else {
        const mockStudent = MOCK_STUDENTS.find(s => 
            (s.usn?.toLowerCase() === lowerSearch || s.name.toLowerCase() === lowerSearch) && 
            s.password === password
        );
        if (mockStudent) {
            return await storageService.autoSeedUser(mockStudent);
        }
    }
    return null;
  },

  autoSeedUser: async (mockUser: User): Promise<User> => {
      let query = supabase.from('users').select('*').eq('role', mockUser.role);
      if (mockUser.usn) {
          query = query.eq('usn', mockUser.usn);
      } else {
          query = query.eq('name', mockUser.name);
      }

      const { data: existing } = await query.maybeSingle();
      if (existing) return existing as User;

      const { data: newUser, error } = await supabase.from('users').insert([{
             name: mockUser.name,
             usn: mockUser.usn,
             role: mockUser.role,
             password: mockUser.password,
             canApprove: mockUser.role === 'HOD' ? true : !!mockUser.canApprove
        }]).select().single();

      if (error) throw error;
      return newUser as User;
  },

  registerStudent: async (name: string, usn: string, password: string): Promise<User> => {
    const { data: existing } = await supabase
        .from('users')
        .select('id')
        .eq('role', 'STUDENT')
        .eq('usn', usn)
        .maybeSingle();

    if (existing) {
        throw new Error("A student with this USN is already registered.");
    }

    const { data, error } = await supabase
      .from('users')
      .insert([{ name, usn, password, role: 'STUDENT' }])
      .select()
      .single();

    if (error) throw error;
    return data as User;
  },

  updateUser: async (updatedUser: User): Promise<void> => {
    const { error } = await supabase
      .from('users')
      .update({
        name: updatedUser.name,
        profilePic: updatedUser.profilePic,
        canApprove: updatedUser.canApprove
      })
      .eq('id', updatedUser.id);
    if (error) throw error;
  },

  seedStudents: async (): Promise<void> => {
    const studentsToSeed = MOCK_STUDENTS.map(s => ({
      name: s.name,
      usn: s.usn,
      role: s.role,
      password: s.password,
      canApprove: false
    }));

    const { error } = await supabase.from('users').upsert(studentsToSeed, { onConflict: 'usn' });
    if (error) throw error;
  },

  getApplications: async (): Promise<LeaveApplication[]> => {
    const { data, error } = await supabase
      .from('applications')
      .select('*')
      .order('timestamp', { ascending: false });
    if (error) throw error;
    return (data as LeaveApplication[]) || [];
  },

  saveApplication: async (app: LeaveApplication): Promise<void> => {
    // Ensure data is flat and null for optional fields
    const payload = {
      ...app,
      studentProfilePic: app.studentProfilePic || null,
      imageUrl: app.imageUrl || null,
      reviewedAt: app.reviewedAt || null,
      assignedTeacherId: app.assignedTeacherId || null
    };

    const { error } = await supabase.from('applications').insert([payload]);
    if (error) {
        console.error("Supabase Save Error:", error);
        throw error;
    }
  },

  updateApplicationStatus: async (appId: string, status: 'APPROVED' | 'REJECTED' | 'PENDING'): Promise<void> => {
    const { error } = await supabase
      .from('applications')
      .update({ status, reviewedAt: new Date().toISOString() })
      .eq('id', appId);
    if (error) throw error;
  },

  togglePriority: async (appId: string, isPriority: boolean): Promise<void> => {
    const { error } = await supabase
      .from('applications')
      .update({ isPriority })
      .eq('id', appId);
    if (error) throw error;
  },

  assignApplication: async (appId: string, teacherId: string | null): Promise<void> => {
    const { error } = await supabase
      .from('applications')
      .update({ assignedTeacherId: teacherId })
      .eq('id', appId);
    if (error) throw error;
  },

  updateFacultyPermission: async (userId: string, canApprove: boolean): Promise<void> => {
    const { error } = await supabase
      .from('users')
      .update({ canApprove })
      .eq('id', userId);
    if (error) throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { Login } from './pages/Login';
import { StudentDashboard } from './pages/StudentDashboard';
import { TeacherDashboard } from './pages/TeacherDashboard';
import { User } from './types';
import { storageService } from './services/storageService';
import { isSupabaseConfigured } from './services/supabaseClient';
import { Database, AlertTriangle, Terminal, CheckCircle, Copy } from 'lucide-react';

function App() {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isConfigured, setIsConfigured] = useState(true);
  const [schemaMissing, setSchemaMissing] = useState(false);
  const [isCopied, setIsCopied] = useState(false);

  const startupCheck = async () => {
    setIsLoading(true);

    if (!isSupabaseConfigured()) {
      setIsConfigured(false);
      setIsLoading(false);
      return;
    }

    try {
      const dbCheck = await storageService.checkDatabaseConnection();

      // PGRST205 means table does not exist
      if (!dbCheck.ok && dbCheck.code === 'PGRST205') {
        setSchemaMissing(true);
      } else if (dbCheck.ok) {
        setSchemaMissing(false);
        const session = localStorage.getItem('unievent_session');
        if (session) {
          setUser(JSON.parse(session));
        }
      }
    } catch (err) {
      console.error("Startup check failed", err);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    startupCheck();
  }, []);

  const handleLogin = (loggedInUser: User) => {
    setUser(loggedInUser);
    localStorage.setItem('unievent_session', JSON.stringify(loggedInUser));
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('unievent_session');
  };

  const copySql = () => {
    navigator.clipboard.writeText(storageService.REQUIRED_SQL);
    setIsCopied(true);
    setTimeout(() => setIsCopied(false), 2000);
  };

  // 1. Connection Required Screen
  if (!isConfigured) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50 p-4">
        <div className="max-w-md w-full bg-white rounded-2xl shadow-xl p-8 border border-orange-100 text-center">
          <div className="w-16 h-16 bg-orange-100 text-orange-600 rounded-full flex items-center justify-center mx-auto mb-6">
            <Database className="w-8 h-8" />
          </div>
          <h1 className="text-2xl font-bold text-gray-900 mb-2">Connect Database</h1>
          <p className="text-gray-600 mb-6">Connect your Supabase project to get started.</p>
          <div className="bg-yellow-50 border border-yellow-200 rounded-lg p-4 text-left mb-6">
            <p className="text-sm text-yellow-700">Open <b>services/supabaseClient.ts</b> and add your URL and Anon Key.</p>
          </div>
          <button onClick={() => window.location.reload()} className="w-full bg-orange-600 text-white font-bold py-3 rounded-xl shadow-lg">Refresh</button>
        </div>
      </div>
    );
  }

  // 2. Schema Missing Screen (Setup Wizard)
  if (schemaMissing) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-900 p-4 font-sans">
        <div className="max-w-2xl w-full bg-gray-800 rounded-3xl shadow-2xl border border-gray-700 overflow-hidden flex flex-col max-h-[90vh]">
          <div className="p-8 bg-gradient-to-r from-orange-600 to-orange-500 text-white">
            <div className="flex items-center gap-3 mb-2">
              <Terminal className="w-6 h-6" />
              <h1 className="text-2xl font-bold">SQL Setup Required</h1>
            </div>
            <p className="text-orange-100">Tables are missing in your Supabase database. Follow these steps:</p>
          </div>

          <div className="p-8 space-y-6 flex-1 overflow-y-auto">
            <div className="space-y-4">
              <div className="flex gap-4">
                <div className="w-8 h-8 rounded-full bg-orange-500/20 text-orange-500 flex items-center justify-center font-bold shrink-0">1</div>
                <p className="text-gray-300">Open your <b>Supabase Dashboard</b> and go to the <b>SQL Editor</b>.</p>
              </div>
              <div className="flex gap-4">
                <div className="w-8 h-8 rounded-full bg-orange-500/20 text-orange-500 flex items-center justify-center font-bold shrink-0">2</div>
                <p className="text-gray-300">Create a <b>New Query</b> and paste the code below.</p>
              </div>
              <div className="flex gap-4">
                <div className="w-8 h-8 rounded-full bg-orange-500/20 text-orange-500 flex items-center justify-center font-bold shrink-0">3</div>
                <p className="text-gray-300">Click <b>Run</b> to create the tables and RLS policies.</p>
              </div>
            </div>

            <div className="relative group">
              <div className="absolute top-4 right-4 z-10">
                <button 
                  onClick={copySql}
                  className="bg-gray-700 hover:bg-gray-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 text-sm transition-all"
                >
                  {isCopied ? <CheckCircle className="w-4 h-4 text-green-400" /> : <Copy className="w-4 h-4" />}
                  {isCopied ? 'Copied!' : 'Copy SQL'}
                </button>
              </div>
              <pre className="bg-gray-950 p-6 rounded-2xl text-orange-400 font-mono text-sm overflow-x-auto border border-gray-800 max-h-60">
                {storageService.REQUIRED_SQL.trim()}
              </pre>
            </div>
          </div>

          <div className="p-8 bg-gray-800/50 border-t border-gray-700">
             <button 
                onClick={startupCheck}
                className="w-full bg-white text-gray-900 font-bold py-4 rounded-2xl hover:bg-orange-50 transition-colors flex items-center justify-center gap-2"
              >
                I've Run the SQL, Re-check Connection
              </button>
          </div>
        </div>
      </div>
    );
  }

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50 flex-col gap-4">
        <div className="w-10 h-10 border-4 border-orange-200 border-t-orange-600 rounded-full animate-spin"></div>
        <div className="text-gray-400 font-medium font-sans">Checking Connection...</div>
      </div>
    );
  }

  if (!user) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <>
      {user.role === 'STUDENT' ? (
        <StudentDashboard user={user} onLogout={handleLogout} />
      ) : (
        <TeacherDashboard user={user} onLogout={handleLogout} />
      )}
    </>
  );
}

export default App;
